import { products } from "../data.js";
import type { Product } from "../types.js";
import { ServiceError } from "./service-error.js";

export interface ProductListOptions {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductListResult {
  products: Product[];
  summary: {
    count: number;
    totalInventoryValue: number;
    averagePrice: number;
  };
}

export interface ProductDetail extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export function listProducts(options: ProductListOptions): ProductListResult {
  let filtered = [...products];

  if (options.category !== undefined) {
    filtered = filtered.filter((p) => p.category === options.category);
  }

  if (options.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= options.minPrice!);
  }

  if (options.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= options.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

export function getProductById(id: number): ProductDetail {
  const product = products.find((p) => p.id === id);
  if (!product) {
    throw new ServiceError("Product not found", 404);
  }

  const isLowStock = product.stock < 10;
  const inventoryValue = Math.round(product.price * product.stock * 100) / 100;

  return {
    ...product,
    isLowStock,
    inventoryValue,
  };
}

