import {
  listProducts,
  getProductById,
  adjustStock,
} from "../services/product-service.js";
import { ServiceError } from "../services/service-error.js";

const router = Router();

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const options: { category?: string; minPrice?: number; maxPrice?: number } =
    {};

  if (category && typeof category === "string") {
    options.category = category;
  }

  if (minPrice && typeof minPrice === "string") {
    const min = parseFloat(minPrice);
    if (!isNaN(min)) options.minPrice = min;
  }

  if (maxPrice && typeof maxPrice === "string") {
    const max = parseFloat(maxPrice);
    if (!isNaN(max)) options.maxPrice = max;
  }

  res.json(listProducts(options));
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    res.json(getProductById(id));
  } catch (err) {
    if (err instanceof ServiceError)
      res.status(err.status).json({ error: err.message });
    else throw err;
  }
});

